const DURABLE_STORE_DIRS: readonly string[] = [
  'lead-capture',
  'investor-crm',
  'deal-tracking',
  'deal-packet',
  'outreach',
  'capital-pipeline',
  'capital-network',
];

let migrationDone = false;

/**
 * One-time, idempotent migration: if the durable root differs from process.cwd()
 * (i.e. we're on the Render persistent disk) and a business store exists in the old
 * cwd location but NOT yet on the durable disk, copy it over so historical leads,

export interface RecordAuditInput {
  actorUserId?: string;
  actorAdminId?: string;
  actorEmail?: string;
  action: string;
  targetUserId?: string;
  targetEntity?: string;
  targetId?: string;
  ip?: string;
  device?: string;
  oldValue?: unknown;
  newValue?: unknown;
  reason?: string;
  metadata?: Record<string, unknown>;
}

export async function recordProtectionAudit(input: RecordAuditInput): Promise<AuditLogEntry> {
  const entry: AuditLogEntry = {
    id: makeId('aud'),
    actorUserId: input.actorUserId ?? '',
    actorAdminId: input.actorAdminId ?? '',
    actorEmail: input.actorEmail ?? '',
    action: input.action,
    targetUserId: input.targetUserId ?? '',
    targetEntity: input.targetEntity ?? '',
    targetId: input.targetId ?? '',
    ip: input.ip ?? '',
    device: input.device ?? '',
    oldValue: input.oldValue ?? null,
    newValue: input.newValue ?? null,
    reason: input.reason ?? '',
    metadata: input.metadata ?? {},
    createdAt: nowIso(),
  };
  await appendAuditLogEvent(entry as unknown as Record<string, unknown>);
  return entry;
}

export async function listProtectionAudit(filters: {
  targetUserId?: string;
  action?: string;
  limit?: number;
} = {}): Promise<AuditLogEntry[]> {
  // Durable store fs fallback: read the jsonl file.
  try {
    const raw = await readFile(AUDIT_LOG_FILE(), 'utf8');
    const lines = raw.split('\n').filter(Boolean);
    let entries = lines.map((l) => JSON.parse(l) as AuditLogEntry);
    if (filters.targetUserId) {
      entries = entries.filter((e) => e.targetUserId === filters.targetUserId);
    }
    if (filters.action) {
      entries = entries.filter((e) => e.action === filters.action);
    }
    entries.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
    return entries.slice(0, filters.limit ?? 500);
  } catch {
    return [];
  }
}

// ---------------------------------------------------------------------------
// 2. Account state machine — deletion protection
// ---------------------------------------------------------------------------

export async function getAccountStateRecord(userId: string): Promise<AccountStateRecord> {
  const states = await readStore<AccountStateRecord[]>(ACCOUNT_STATES_FILE(), []);
  let record = states.find((s) => s.userId === userId);
  if (!record) {
    record = {
      id: makeId('st'),
      userId,
      accountState: 'active',
      reason: 'initial',
      operatorId: '',
      operatorEmail: '',
      previousState: 'active',
      hasFunds: false,
      immutableFinancialHistory: true,
      metadata: {},
      updatedAt: nowIso(),
      createdAt: nowIso(),
    };
    states.push(record);
    await writeStore(ACCOUNT_STATES_FILE(), states);
  }
  return record;
}

export async function listAccountStates(filter?: { state?: AccountState }): Promise<AccountStateRecord[]> {
  const states = await readStore<AccountStateRecord[]>(ACCOUNT_STATES_FILE(), []);
  return filter?.state ? states.filter((s) => s.accountState === filter.state) : states;
}

export interface TransitionStateInput {
  userId: string;
  newState: AccountState;
  reason: string;
  operatorId: string;
  operatorEmail: string;
  hasFunds?: boolean;
  ip?: string;
  device?: string;
}

